import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { MQTT_BROKERS } from "../utils/constants";
import { useProtocols } from "../hooks/useprotocols";
import { validateConnection, createConnection } from "../api/connectionsapi";

/* â”€â”€ Success Popup â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */
const SuccessPopup = ({ message }) => (
  <div style={{
    position: "fixed",
    bottom: "30px",
    right: "30px",
    zIndex: 9999,
    backgroundColor: "#198754",
    color: "#fff",
    padding: "14px 22px",
    borderRadius: "12px",
    boxShadow: "0 4px 20px rgba(0,0,0,0.3)"
  }}>
    âś… {message}
  </div>
);

/* â”€â”€ Connection Page â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */
const Connection = () => {
  const [selectedProtocol, setSelectedProtocol] = useState("");
  const [showModal, setShowModal] = useState(false);
  const navigate = useNavigate();
  const { protocols, loading } = useProtocols();

  const handleConnected = () => {
    setShowModal(false);
    navigate("/sensor", { state: { showSuccess: true } });
  };

  return (
    <div>
      <select
        value={selectedProtocol}
        onChange={(e) => {
          setSelectedProtocol(e.target.value);
          setShowModal(true);
        }}
      >
        <option value="">Select Protocol</option>
        {!loading && protocols.map((p) =>
          <option key={p} value={p}>{p}</option>
        )}
      </select>

      {showModal && selectedProtocol === "MQTT" && (
        <MqttForm onConnected={handleConnected} onClose={() => setShowModal(false)} />
      )}
    </div>
  );
};

/* â”€â”€ MQTT Form (FIXED & SIMPLE) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */
const MqttForm = ({ onConnected, onClose }) => {
  const [tab, setTab] = useState("basic");
  const [status, setStatus] = useState("idle");
  const [error, setError] = useState("");

  /* âś… BASIC BROKER STATE */
  const [selectedBrokerName, setSelectedBrokerName] = useState(
    MQTT_BROKERS[0]?.name || ""
  );
  const [port, setPort] = useState(MQTT_BROKERS[0]?.port || "");
  const [ssl, setSsl] = useState(MQTT_BROKERS[0]?.ssl || false);
  const [connectionName, setConnectionName] = useState("");

  /* âś… CUSTOM BROKER STATE */
  const [custom, setCustom] = useState({
    ip: "",
    port: "",
    connectionName: "",
    username: "",
    password: "",
    ssl: false
  });

  const selectedBroker =
    MQTT_BROKERS.find(b => b.name === selectedBrokerName) || MQTT_BROKERS[0];

  const connectionString =
    tab === "basic"
      ? `${ssl ? "wss" : "ws"}://${selectedBroker.host}:${port}`
      : `${custom.ssl ? "wss" : "ws"}://${custom.ip}:${custom.port}`;

  const handleConnect = async () => {
    setStatus("connecting");
    setError("");

    const isCustom = tab === "custom";

    const validatePayload = {
      connectionUrl: isCustom ? custom.ip : selectedBroker.host,
      port: isCustom ? Number(custom.port) : Number(port),
      tlsEnabled: isCustom ? custom.ssl : ssl,
      isPublic: !isCustom,
      username: isCustom ? custom.username : null,
      password: isCustom ? custom.password : null
    };

    const createPayload = {
      protocol: "MQTT",
      connectionName: isCustom ? custom.connectionName : connectionName,
      ...validatePayload
    };

    try {
      const v = await validateConnection(validatePayload);
      if (v?.message === "Connection is subscribable.") {
        const c = await createConnection(createPayload);
        localStorage.setItem("sb_connectionId", c.connectionId);
        onConnected();
      } else {
        setError("Broker not reachable");
      }
    } catch (e) {
      setError(e.message || "Connection failed");
    } finally {
      setStatus("idle");
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <h4>MQTT Connection</h4>

      <button onClick={() => setTab("basic")}>Basic</button>
      <button onClick={() => setTab("custom")}>Custom</button>

      {tab === "basic" && (
        <>
          <select
            value={selectedBrokerName}
            onChange={(e) => {
              const b = MQTT_BROKERS.find(x => x.name === e.target.value);
              setSelectedBrokerName(b.name);
              setPort(b.port);
              setSsl(b.ssl);
            }}
          >
            {MQTT_BROKERS.map(b =>
              <option key={b.name}>{b.name}</option>
            )}
          </select>

          <input value={port} onChange={(e) => setPort(e.target.value)} />
          <input
            placeholder="Connection Name"
            value={connectionName}
            onChange={(e) => setConnectionName(e.target.value)}
          />
          <label>
            SSL <input type="checkbox" checked={ssl} onChange={(e) => setSsl(e.target.checked)} />
          </label>
        </>
      )}

      {tab === "custom" && (
        <>
          <input placeholder="IP" onChange={(e) => setCustom({ ...custom, ip: e.target.value })} />
          <input placeholder="Port" onChange={(e) => setCustom({ ...custom, port: e.target.value })} />
          <input placeholder="Connection Name" onChange={(e) => setCustom({ ...custom, connectionName: e.target.value })} />
        </>
      )}

      <pre>{connectionString}</pre>

      {error && <p style={{ color: "red" }}>{error}</p>}

      <button onClick={handleConnect} disabled={status === "connecting"}>
        Connect
      </button>
      <button onClick={onClose}>Cancel</button>
    </div>
  );
};

/* â”€â”€ Placeholder â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */
const PlaceholderForm = ({ protocol }) => (
  <div>{protocol} coming soon</div>
);

export default Connection;
``
